using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth;
    public int currency = 0;

    void Awake()
    {
        // Initialize current health to max health at the start of the game
        currentHealth = maxHealth;
    }

    // Call this method when the player takes damage
    public void TakeDamage(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Damage amount cannot be negative.");
            return;
        }

        currentHealth -= amount;
        if (currentHealth < 0)
        {
            currentHealth = 0;
        }

        Debug.Log($"Player took {amount} damage. Current Health: {currentHealth}");

        if (currentHealth == 0)
        {
            Debug.Log("Player has been defeated!");
            // Implement game over logic here (e.g., scene reload, UI prompt)
        }
    }

    // Call this method when the player heals
    public void Heal(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Heal amount cannot be negative.");
            return;
        }

        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }

        Debug.Log($"Player healed {amount} health. Current Health: {currentHealth}");
    }

    // Call this method to add currency to the player
    public void AddCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Cannot add negative currency.");
            return;
        }

        currency += amount;
        Debug.Log($"Added {amount} currency. Total currency: {currency}");
    }

    // Call this method to try and spend currency. Returns true if successful, false otherwise.
    public bool TrySpendCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogError("Cannot spend negative currency.");
            return false;
        }

        if (currency >= amount)
        {
            currency -= amount;
            Debug.Log($"Spent {amount} currency. Remaining currency: {currency}");
            return true;
        }
        else
        {
            Debug.LogWarning($"Not enough currency to spend {amount}. Current currency: {currency}");
            return false;
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats; // Assign your PlayerStats component in the Inspector
    public List<ShopItem> availableItems = new List<ShopItem>();

    // Client-side damage calculation example
    public int CalculateDamage(int baseAttackPower, int targetDefense)
    {
        int calculatedDamage = baseAttackPower - targetDefense;
        if (calculatedDamage < 0)
        {
            calculatedDamage = 0; // Damage cannot be negative
        }
        return calculatedDamage;
    }

    // Client-side price calculation example (can be dynamic based on player level, discounts, etc.)
    public int GetItemPrice(ShopItem item)
    {
        // For simplicity, this example just returns the base price.
        // You could add complex logic here:
        // int finalPrice = item.basePrice;
        // if (playerStats.level > 10) finalPrice = (int)(finalPrice * 0.9f); // 10% discount
        // return finalPrice;
        return item.basePrice;
    }

    // Call this method when the player attempts to purchase an item
    public bool TryPurchaseItem(ShopItem item)
    {
        if (playerStats == null)
        {
            Debug.LogError("PlayerStats reference is missing in ShopManager. Please assign it in the Inspector.");
            return false;
        }

        int price = GetItemPrice(item);

        if (playerStats.currency >= price)
        {
            if (playerStats.TrySpendCurrency(price))
            {
                ApplyItemEffect(item);
                Debug.Log($"Successfully purchased '{item.itemName}' for {price} currency.");
                return true;
            }
        }
        Debug.LogWarning($"Failed to purchase '{item.itemName}'. Not enough currency or another issue.");
        return false;
    }

    // Applies the effect of the purchased item to the player
    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.effectType)
        {
            case ItemEffectType.RestoreHealth:
                playerStats.Heal(item.effectAmount);
                break;
            case ItemEffectType.GrantCurrency:
                playerStats.AddCurrency(item.effectAmount);
                break;
            case ItemEffectType.None:
                Debug.Log($"Item '{item.itemName}' has no defined effect.");
                break;
            default:
                Debug.LogWarning($"Unhandled item effect type for '{item.itemName}': {item.effectType}");
                break;
        }
    }
